        public override async Task Validation(OtherSections item, Result<OtherSections> executionResult)
        {
            if (await UOW.GetRepositoryAsync<OtherSections>().HasRecordsAsync(x => x.Name == item.Name && x.Status == true && x.ID != item.ID))
            {
                executionResult.AddMessageItem(new MessageItem(nameof(OtherSections.Name), "Section Name already exists"));
            }
        }
        public override async Task<OtherSections> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<OtherSections>().SingleAsync(
                predicate: x => x.ID == id,
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IEnumerable<OtherSections>> GetList(string orderBy)
        {
            return await UOW.GetRepositoryAsync<OtherSections>().GetListAsync(orderBy, x => x.Status == true);
        }

        public override async Task<IPaginate<OtherSections>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<OtherSections>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Name.Contains(search.Name)),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Name", ascending: !search.IsDescend);
